const body = $json.body || $json;

const required = ['customer_name','email','phone','cart'];
const missing = required.filter(k => !body[k] || (Array.isArray(body[k]) && body[k].length === 0));
if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRegex.test(body.email)) {
  throw new Error('Invalid email format');
}

const phoneDigits = String(body.phone).replace(/\D/g, '');
if (phoneDigits.length < 10) {
  throw new Error('Invalid phone number');
}

if (!Array.isArray(body.cart) || body.cart.length === 0) {
  throw new Error('cart must be non-empty array');
}

// Calculate totals if not provided
let subtotal = 0;
body.cart.forEach(function(item) {
  subtotal += (item.price * (item.qty || 1));
});

const taxRate = 0.0952;
const tax = Math.round(subtotal * taxRate * 100) / 100;
const total = Math.round((subtotal + tax) * 100) / 100;

const now = new Date();
const cst = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));
const ymd = cst.toISOString().slice(0,10).replace(/-/g, '');
const seq = String(Math.floor(Math.random() * 900) + 100).padStart(3, '0');
const order_id = 'UDO-' + ymd + '-' + seq;

return [{
  json: {
    ...body,
    subtotal: body.subtotal || subtotal.toFixed(2),
    tax: body.tax || tax.toFixed(2),
    total: body.total || total.toFixed(2),
    order_id: body.order_id || order_id,
    phone_digits: phoneDigits,
    pickup_time: body.pickup_time || 'ASAP',
    validated_at: cst.toISOString()
  }
}];

const body = $json;
const cart = body.cart || [];

const lineItems = cart.map(function(item) {
  var lineItem = {
    name: item.name,
    quantity: String(item.qty || 1),
    base_price_money: {
      amount: Math.round(item.price * 100),
      currency: 'USD'
    },
    modifiers: []
  };

  if (Array.isArray(item.modifiers)) {
    item.modifiers.forEach(function(mod) {
      var deltaCents = Math.round(Number(mod.price_delta || 0) * 100);
      lineItem.modifiers.push({
        name: mod.mod_name || mod.name || 'Modifier',
        base_price_money: {
          amount: deltaCents,
          currency: 'USD'
        }
      });
    });
  }

  return lineItem;
});

// Add tax as line item
lineItems.push({
  name: 'Tax',
  quantity: '1',
  base_price_money: {
    amount: Math.round(parseFloat(body.tax) * 100),
    currency: 'USD'
  },
  modifiers: []
});

return [{
  json: {
    ...body,
    square_line_items: lineItems,
    subtotal_cents: Math.round(parseFloat(body.subtotal) * 100),
    tax_cents: Math.round(parseFloat(body.tax) * 100),
    total_cents: Math.round(parseFloat(body.total) * 100)
  }
}];

