const body = $json.body || $json;

if (body.source !== 'meal-prep') {
  throw new Error('Invalid source: expected meal-prep');
}

const required = ['customer','items','pricing'];
const missing = required.filter(k => !body[k]);
if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

const cust = body.customer;
if (!cust.name || !cust.phone || !cust.email) {
  throw new Error('Missing customer name, phone, or email');
}

const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (!emailRe.test(cust.email)) {
  throw new Error('Invalid email format');
}

const phoneDigits = String(cust.phone).replace(/\D/g, '');
if (phoneDigits.length < 10) {
  throw new Error('Invalid phone number');
}

const items = body.items || [];
if (!Array.isArray(items) || items.length === 0) {
  throw new Error('At least one meal required');
}

const pricing = body.pricing || {};
const expectedTotal = (pricing.subtotal || 0) + (pricing.labor || 0) + (pricing.tax || 0);
if (Math.abs(expectedTotal - (pricing.total || 0)) > 2) {
  throw new Error('Pricing calculation mismatch');
}

// DEADLINE: Order by Wednesday 12:00 PM CT
const now = new Date();
const cstTime = new Date(now.toLocaleString('en-US', { timeZone: 'America/Chicago' }));
const day = cstTime.getDay();
const hour = cstTime.getHours();
const isOrderingClosed = (day === 3 && hour >= 12) || day === 4 || (day === 5 && hour < 12);
if (isOrderingClosed) {
  throw new Error('Orders are closed. Ordering reopens Friday at 12:00 PM for next week.');
}

// Next Thursday pickup
const pickupDate = new Date(cstTime);
const daysUntilThu = (4 - day + 7) % 7 || 7;
pickupDate.setDate(pickupDate.getDate() + daysUntilThu);
const pickupDateStr = pickupDate.toISOString().split('T')[0];

// Order ID
const ymd = cstTime.toISOString().slice(0,10).replace(/-/g, '');
const seq = String(Math.floor(Math.random() * 900) + 100).padStart(3, '0');
const order_id = 'UMP-' + ymd + '-' + seq;

return [{
  json: {
    ...body,
    order_id,
    phone_digits: phoneDigits,
    pickup_date: pickupDateStr,
    validated_at: cstTime.toISOString(),
    ordering_open: true
  }
}];

const input = $json;
const items = input.items || [];

const lineItems = items.map(function(item) {
  return {
    name: item.name,
    quantity: String(item.qty),
    base_price_money: {
      amount: item.price,
      currency: 'USD'
    },
    modifiers: []
  };
});

lineItems.push({
  name: 'Labor & Packaging',
  quantity: '1',
  base_price_money: {
    amount: input.pricing.labor,
    currency: 'USD'
  },
  modifiers: []
});

lineItems.push({
  name: 'Tax (6.5%)',
  quantity: '1',
  base_price_money: {
    amount: input.pricing.tax,
    currency: 'USD'
  },
  modifiers: []
});

const payload = {
  idempotency_key: input.order_id,
  order: {
    location_id: 'J4B6A3X6RYA63',
    reference_id: input.order_id,
    line_items: lineItems,
    note: 'Meal Prep Order - Weekly pre-made meals\nSource: Utopia Deli Meal Prep System',
    metadata: {
      order_type: 'meal_prep',
      subtotal_cents: String(input.pricing.subtotal),
      labor_cents: String(input.pricing.labor),
      tax_cents: String(input.pricing.tax),
      total_cents: String(input.pricing.total),
      tax_rate_percent: '6.5',
      tax_handling: 'manual_line_item',
      order_system: 'utopia_deli_meal_prep',
      pickup_date: input.pickup_date
    }
  },
  checkout_options: {
    redirect_url: 'https://order.theutopiadeli.com/payment-confirmed-meal-prep/?order_id=' + input.order_id,
    merchant_support_email: 'theutopiadelilittlerock@gmail.com',
    ask_for_shipping_address: false,
    allow_tipping: false
  },
  pre_populated_data: {
    buyer_email: input.customer.email,
    buyer_phone_number: input.phone_digits,
    buyer_address: {
      first_name: input.customer.name.split(' ')[0] || input.customer.name,
      last_name: input.customer.name.split(' ').slice(1).join(' ') || ''
    }
  }
};

return [{
  json: {
    ...input,
    square_payload: payload,
    square_total: input.pricing.total
  }
}];

